Here's a modern MSTest approach for testing your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs beyond 5s
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ThrowsHttpRequestException_WhenResponseIsError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ThrowsOperationCanceledException_WhenCancelled()
    {
        var handler = new MockHttpMessageHandler("content", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Pre-cancel

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesCancellationToken_ToHttpClient()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        await fetcher.FetchAsync("https://example.com", cts.Token);

        Assert.AreEqual(cts.Token, handler.ReceivedCancellationToken);
    }

    // Testable handler — no mocking framework needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public CancellationToken ReceivedCancellationToken { get; private set; }

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            ReceivedCancellationToken = cancellationToken;

            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` return | MSTest natively awaits test methods — no `Task.Result` hacks |
| `[Timeout(ms)]` | Guards against hangs; fails deterministically instead of blocking CI |
| `Assert.ThrowsExactlyAsync` | MSTest v3+ preferred over `ThrowsExceptionAsync` (exact type match) |
| `CancellationToken` forwarding | Verifies the token reaches the dependency |
| Pre-cancelled token | Tests the immediate-cancel path without races |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP behavior |

**Tip:** Always pair `[Timeout]` with async tests to prevent CI deadlocks if an `await` never completes.
